```python
import os
from collections import OrderedDict

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        self.caches = {}

    def get_cache(self, index_file):
        cache_key = os.path.basename(index_file)
        if cache_key not in self.caches:
            self.caches[cache_key] = OrderedDict()
        return self.caches[cache_key]

    def set(self, index_file, key, value):
        cache = self.get_cache(index_file)
        cache[key] = value

    def get(self, index_file, key):
        cache = self.get_cache(index_file)
        return cache.get(key)

    def delete(self, index_file, key):
        cache = self.get_cache(index_file)
        if key in cache:
            del cache[key]

    def clear(self, index_file):
        cache = self.get_cache(index_file)
        cache.clear()

    def close(self):
        for cache in self.caches.values():
            cache.clear()

# Usage
